parameters.jsCode:
// Bambu printers wrap status inside a 'print' key
const p = $json?.print ?? $json;

return {
  // identity
  printer_model:   $json?.info?.machine_type ?? 'unknown',
  // print job
  gcode_state:     p.gcode_state ?? 'unknown',
  print_percent:   p.mc_percent ?? 0,
  remaining_min:   p.mc_remaining_time ?? null,
  task_name:       p.subtask_name ?? '',
  // temperatures
  nozzle_temp:     p.nozzle_temper ?? null,
  nozzle_target:   p.nozzle_target_temper ?? null,
  bed_temp:        p.bed_temper ?? null,
  bed_target:      p.bed_target_temper ?? null,
  // fan speeds
  fan_gear:        p.fan_gear ?? null,
  heatbreak_fan:   p.heatbreak_fan_speed ?? null,
  // error
  error_code:      p.print_error ?? 0,
  // raw in case you need to inspect further
  _raw:            $json
};
